import pygame
import sys
import random

pygame.init()

width, height = 800, 600
screen = pygame.display.set_mode((width, height))
pygame.display.set_caption('Snake Game')
clock = pygame.time.Clock()

class SnakeGame:
    def __init__(self):
        self.snake = [(200, 200), (220, 200), (240, 200)]
        self.direction = 'right'
        self.food = self.generate_food()

    def generate_food(self):
        while True:
            x = random.randint(0, width - 20) // 20 * 20
            y = random.randint(0, height - 20) // 20 * 20
            food = (x, y)
            if food not in self.snake:
                return food

    def draw_snake(self):
        for pos in self.snake:
            pygame.draw.rect(screen, (0, 255, 0), (pos[0], pos[1], 20, 20))

    def draw_food(self):
        pygame.draw.rect(screen, (255, 0, 0), (self.food[0], self.food[1], 20, 20))

    def update_snake(self):
        head = self.snake[-1]
        if self.direction == 'right':
            new_head = (head[0] + 20, head[1])
        elif self.direction == 'left':
            new_head = (head[0] - 20, head[1])
        elif self.direction == 'up':
            new_head = (head[0], head[1] - 20)
        elif self.direction == 'down':
            new_head = (head[0], head[1] + 20)

        self.snake.append(new_head)
        if self.food == new_head:
            self.food = self.generate_food()
        else:
            self.snake.pop(0)

    def check_collision(self):
        head = self.snake[-1]
        if (head[0] < 0 or head[0] >= width or
            head[1] < 0 or head[1] >= height or
            head in self.snake[:-1]):
            return True
        return False

def main():
    game = SnakeGame()
    while True:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT and game.direction != 'right':
                    game.direction = 'left'
                elif event.key == pygame.K_RIGHT and game.direction != 'left':
                    game.direction = 'right'
                elif event.key == pygame.K_UP and game.direction != 'down':
                    game.direction = 'up'
                elif event.key == pygame.K_DOWN and game.direction != 'up':
                    game.direction = 'down'

        screen.fill((0, 0, 0))
        game.update_snake()
        game.draw_snake()
        game.draw_food()

        if game.check_collision():
            print('Game Over')
            break

        pygame.display.update()
        clock.tick(10)

if __name__ == '__main__':
    main()

